-- ═══════════════════════════════════════════════════════════════
-- 8. CASH FLOW / PAYMENT MILESTONES
-- No existing table — create it, then populate
-- ═══════════════════════════════════════════════════════════════
CREATE TABLE IF NOT EXISTS payment_milestones (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  org_id UUID NOT NULL REFERENCES orgs(id) ON DELETE CASCADE,
  project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,
  description TEXT NOT NULL,
  amount DECIMAL NOT NULL DEFAULT 0,
  received_amount DECIMAL DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending', 'invoiced', 'received', 'overdue')),
  due_date DATE,
  payment_date DATE,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_payment_milestones_project ON payment_milestones(project_id);
CREATE INDEX IF NOT EXISTS idx_payment_milestones_org ON payment_milestones(org_id);
ALTER TABLE payment_milestones DISABLE ROW LEVEL SECURITY;

